input.query:
//Summary of host utilization
timeseries { cpu_p90 = percentile(dt.host.cpu.usage, 90, rollup:max, scalar: true), mem_p90 = percentile(dt.host.memory.usage, 90, rollup:max, scalar: true) }, 
  union: TRUE, by: { dt.entity.host }, from: now()-30d, to: now()
| fieldsAdd dt.entity.host.name = entityName(dt.entity.host), cpu_p90=round(cpu_p90), mem_p90=round(mem_p90)
| fieldsAdd utilization=coalesce(
  if(cpu_p90 < 10 and mem_p90 < 30, "UNUSED"),
  if(cpu_p90 < 30 and mem_p90 < 50, "OVERPROVISIONED"),
  if(cpu_p90 > 80 and mem_p90 < 85, "UNDERPROVISIONED"),
  "NOMINAL"
)
| summarize {count=count(), examples=collectArray(
  record(dt.entity.host.name, dt.entity.host, cpu_p90, mem_p90, cloudType=entityAttr(dt.entity.host,"cloudType"), instanceType = coalesce(
    if(entityAttr(dt.entity.host,"cloudType")=="EC2",entityAttr(dt.entity.host,"additionalSystemInfo")[system.model]),
    entityAttr(dt.entity.host,"azureVmSizeLabel"),
    entityAttr(dt.entity.host,"gceMachineType")
  ))
,maxLength:5)}, by: {utilization}

